use std::process::Command;
use std::path::Path;

fn convert_file(filename: &str, format: &str) -> Result<String, Box<dyn std::error::Error>> {
    let input_path = Path::new(filename);
    let output_filename = format!("{}.{}", input_path.file_stem().unwrap().to_str().unwrap(), format);
    
    let output_path = input_path.with_file_name(&output_filename);
    
    let output_str = output_path.to_str().unwrap();
    
    let command = match format {
        "pdf" => {
            Command::new("libreoffice")
                .args(&["--headless", "--convert-to", "pdf", "--outdir", output_path.parent().unwrap().to_str().unwrap(), filename])
        },
        "jpg" | "jpeg" => {
            Command::new("convert")
                .args(&[filename, output_str])
        },
        "png" => {
            Command::new("convert")
                .args(&[filename, output_str])
        },
        _ => return Err("Unsupported format".into()),
    };
    
    let output = command.output()?;
    
    if !output.status.success() {
        return Err(format!("Conversion failed: {}", String::from_utf8_lossy(&output.stderr)).into());
    }
    
    Ok(output_str.to_string())
}